        bool[,] visited = new bool[dungeonWidth, dungeonHeight];

        for (int x = 0; x < dungeonWidth; x++) {
            for (int y = 0; y < dungeonHeight; y++) {
                if (dungeonMap[x, y] == targetType && !visited[x, y]) {
                    List<Coord> newRegion = new List<Coord>();
                    GetRegion(x, y, targetType, visited, newRegion);
                    regions.Add(newRegion);
                }
            }
        }

        return regions;
    }

    void GetRegion(int x, int y, int targetType, bool[,] visited, List<Coord> region) {
        Stack<Coord> stack = new Stack<Coord>();
        stack.Push(new Coord(x, y));
        visited[x, y] = true;

        while (stack.Count > 0) {
            Coord current = stack.Pop();
            region.Add(current);

            for (int dx = -1; dx <= 1; dx++) {
                for (int dy = -1; dy <= 1; dy++) {
                    if (dx == 0 && dy == 0) continue;
                    int nx = current.tileX + dx;
                    int ny = current.tileY + dy;

                    if (nx >= 0 && nx < dungeonWidth && ny >= 0 && ny < dungeonHeight && !visited[nx, ny] && dungeonMap[nx, ny] == targetType) {
                        visited[nx, ny] = true;
                        stack.Push(new Coord(nx, ny));
                    }
                }
            }
        }
    }

