        foreach (Coord coord in room.tiles) {
            InstantiateFromArray(roomTiles, coord.tileX, coord.tileY);
        }

        // Place floor tiles
        foreach (Coord coord in room.floorTiles) {
            InstantiateFromArray(floorTiles, coord.tileX, coord.tileY);
        }

        // Place wall tiles
        foreach (Coord coord in room.wallTiles) {
            InstantiateFromArray(wallTiles, coord.tileX, coord.tileY);
        }

        // Place edge tiles
        foreach (Coord coord in room.edgeTiles) {
            InstantiateFromArray(corridorTiles, coord.tileX, coord.tileY);
        }
    }

