    public class Room {
        public List<Coord> tiles = new List<Coord>();
        public List<Coord> floorTiles = new List<Coord>();
        public List<Coord> wallTiles = new List<Coord>();
        public List<Coord> edgeTiles = new List<Coord>();
        public List<Room> connectedRooms = new List<Room>();
        public bool isMainRoom = false;
        public bool isAccessibleFromMainRoom = false;

        public Room(List<Coord> region, int[,] map) {
            foreach (Coord coord in region) {
                tiles.Add(coord);
                if (map[coord.tileX, coord.tileY] == 0) {
                    floorTiles.Add(coord);
                } else {
                    wallTiles.Add(coord);
                }
            }

            // Find edge tiles
            foreach (Coord tile in tiles) {
                bool isEdge = false;
                for (int dx = -1; dx <= 1; dx++) {
                    for (int dy = -1; dy <= 1; dy++) {
                        if (dx == 0 && dy == 0) continue;
                        int nx = tile.tileX + dx;
                        int ny = tile.tileY + dy;

